#!/usr/bin/env bash

DEPENDABOT_CONFIGURATION_FILE=".github/dependabot.yml"

echo "Generating ${DEPENDABOT_CONFIGURATION_FILE}"
cat >"${DEPENDABOT_CONFIGURATION_FILE}" <<EOL
---
# This file is auto-generated by running the below command, do not manually amend.
# bash scripts/dependabot/configuration-generator.sh

version: 2

updates:
  - package-ecosystem: "github-actions"
    directory: "/"
    schedule:
      interval: "daily"
      time: "09:00"
      timezone: "Europe/London"
    cooldown:
      default-days: 7
    commit-message:
      prefix: ":dependabot: github-actions"
      include: "scope"

  - package-ecosystem: "devcontainers"
    directory: "/"
    schedule:
      interval: "daily"
      time: "09:00"
      timezone: "Europe/London"
    cooldown:
      default-days: 7
    commit-message:
      prefix: ":dependabot: devcontainers"
      include: "scope"

  - package-ecosystem: "terraform"
    schedule:
      interval: "daily"
      time: "09:00"
      timezone: "Europe/London"
    cooldown:
      default-days: 7
    open-pull-requests-limit: 15
    commit-message:
      prefix: ":dependabot: terraform"
      include: "scope"
    directories:
EOL

echo "=== Ecosystem: terraform ==="

SEARCH_PATTERN=".terraform.lock.hcl"
SKIP_FILE=".dependabot-terraform-ignore"

folders=$(find . -type f -name "${SEARCH_PATTERN}" -exec dirname {} \; | LC_ALL=C sort | uniq | cut -c 3-)
export folders

echo "=== Folders ==="
echo "${folders}"

for folder in ${folders}; do
  if [[ -f "${folder}/${SKIP_FILE}" ]]; then
    echo "Ignoring ${folder}"
    continue
  fi
  printf "      - \"${folder}\"\n" >>"${DEPENDABOT_CONFIGURATION_FILE}"
done
